mapper.select:
select p.id, p.ent_code, p.out_put_id, p.unit_id, p.sort_order, p.point_name, p.point_type, p.data_type, p.address, p.register_address, p.coefficient, p.unit, p.min_value, p.max_value, p.precision, p.status, p.description, p.update_time, e.ent_name, i.out_put_code, i.out_put_name, e.ent_code as ent_item_code, e.ent_name as ent_item_name from t_ent_plc_info p left join t_ent_out_put_info i on i.out_put_id = p.out_put_id left join t_bas_enterprise e on e.ent_code = i.ent_code where i.ent_code = #{entCode}
and p.status = #{status}
order by p.sort_order desc

mapper.update:
update t_ent_plc_info

    update_time = now()
    , sort_order = #{sortOrder}
    , point_name = #{pointName}
    , point_type = #{pointType}
    , data_type = #{dataType}
    , address = #{address}
    , register_address = #{registerAddress}
    , coefficient = #{coefficient}
    , unit = #{unit}
    , min_value = #{minValue}
    , max_value = #{maxValue}
    , `precision` = #{precision}
    , status = #{status}
    , description = #{description}

where id = #{id}
